    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check first part 0...p is strictly increasing
            let isInc1 = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    isInc1 = false;
                    break;
                }
            }
            if (!isInc1) continue;
            // Check second part p...q is strictly decreasing
            let isDec = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    isDec = false;
                    break;
                }
            }
            if (!isDec) continue;
            // Check third part q...n-1 is strictly increasing
            let isInc2 = true;
            for (let i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    isInc2 = false;
                    break;
                }
            }
            if (isInc2) {
                return true;
            }
        }
    }
    return false;
}

