                if (nums[i] <= nums[i + 1]) {
                    isDec = false;
                    break;
                }
            }
            if (!isDec) continue;
            // Check third part q...n-1 is strictly increasing
            let isInc2 = true;
            for (let i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    isInc2 = false;
                    break;
                }
            }
            if (isInc2) {
                return true;
            }
        }
    }
    return false;
}
